local LMatchThreeGameBaseCtrl = LXImport(".LMatchThreeGameBaseCtrl")

---@class LMatchThreeGameMainRoleCtrl:LMatchThreeGameBaseCtrl
local LMatchThreeGameMainRoleCtrl = LxClass("LMatchThreeGameMainRoleCtrl", LMatchThreeGameBaseCtrl)
-----------------------------------------------------------------

local YXTouchManager = CS.YXTouchManager
local math = math
local typeOfTextMesh = typeof(CS.TextMeshPro)

local RoleScale = Vector3(1, 1, 1)
local RolePrefab = "XR_Zhujue01"

-----------------------------------------------------------------
function LMatchThreeGameMainRoleCtrl:LMatchThreeGameMainRoleCtrl()

end

-- 销毁
function LMatchThreeGameMainRoleCtrl:OnDestroy()
    if self._dpObj then
        self._dpObj:Destroy()
        self._dpObj = nil
    end
end

-- 初始化
function LMatchThreeGameMainRoleCtrl:Init()
    local root    = self:GetMap():GetMapTrans()
    local trans   = CS.FindTrans(root, "LayerRoot/MainRole")
    self._trans   = trans

    local icon    = CS.FindTrans(trans, "Icon")
    local hpTrans = CS.FindTrans(trans, "HpBg/Hp")
    self._hpTxt   = hpTrans:GetComponent(typeOfTextMesh)

    local ref     = gModelMatchThreeGame:GetRef()
    self._curHp   = ref.hp

    self:InitSpine(icon)
    self:Refresh()
end

-- 初始化角色
function LMatchThreeGameMainRoleCtrl:InitSpine(parent)
    local dp = LDisplaySpine:New()
    dp:CreateSpine(parent, RolePrefab)
    self._dpObj = dp
    dp:SetLoadedFunction(function()
        if self:IsDestroy() then return end
        local trans = dp:GetDisplayTrans()
        trans.localScale = RoleScale
    end)
    dp:StartLoad()
end

-- 设置血量
function LMatchThreeGameMainRoleCtrl:SetHp(hp)
    self._curHp = hp
end

-- 获取血量
function LMatchThreeGameMainRoleCtrl:GetHp()
    return self._curHp
end

-- 刷新
function LMatchThreeGameMainRoleCtrl:Refresh()
    local curHp      = self:GetHp()
    curHp            = math.max(curHp, 0)
    self._hpTxt.text = curHp
end

-- 伤害
function LMatchThreeGameMainRoleCtrl:Hurt(value, delayTime)
    local curHp = self:GetHp()
    curHp = math.max(0, curHp - value)
    self:SetHp(curHp)
    self:Refresh()

    local hudCtrl = self:GetCtrl("Hud")
    local pos = self._trans.position
    pos.y = pos.y + 0.5
    pos.x = pos.x + 0.8
    hudCtrl:ShowHud(pos, -value, true, delayTime)


    if curHp == 0 then
        FireEvent(EventNames.MATCH_THREE_GAME_OVER, { isWin = false })
    end

    return curHp == 0
end

return LMatchThreeGameMainRoleCtrl
